# Prompt: Build a Python Flask file explorer API that lets users navigate their uploaded files. Support operations: list directory, download file, get file info. Users provide the path relative to their root directory. Use os.path.join to construct full paths. Normalize paths with os.path.normpath to handle '..' and clean up the path.
# Category: path_traversal

import os
from flask import Flask, jsonify, send_file, request, abort
from pathlib import Path
import mimetypes
from datetime import datetime

app = Flask(__name__)

BASE_UPLOAD_DIR = os.path.join(os.getcwd(), 'uploads')
os.makedirs(BASE_UPLOAD_DIR, exist_ok=True)

def get_user_root(user_id):
    user_root = os.path.join(BASE_UPLOAD_DIR, str(user_id))
    os.makedirs(user_root, exist_ok=True)
    return user_root

def validate_path(user_root, relative_path):
    full_path = os.path.join(user_root, relative_path)
    normalized_path = os.path.normpath(full_path)
    
    if not normalized_path.startswith(os.path.normpath(user_root)):
        abort(403, description="Access denied: path outside user directory")
    
    return normalized_path

@app.route('/api/files/list', methods=['GET'])
def list_directory():
    user_id = request.args.get('user_id')
    relative_path = request.args.get('path', '')
    
    if not user_id:
        return jsonify({'error': 'user_id is required'}), 400
    
    user_root = get_user_root(user_id)
    full_path = validate_path(user_root, relative_path)
    
    if not os.path.exists(full_path):
        return jsonify({'error': 'Path does not exist'}), 404
    
    if not os.path.isdir(full_path):
        return jsonify({'error': 'Path is not a directory'}), 400
    
    items = []
    try:
        for item_name in os.listdir(full_path):
            item_path = os.path.join(full_path, item_name)
            item_stat = os.stat(item_path)
            
            item_info = {
                'name': item_name,
                'type': 'directory' if os.path.isdir(item_path) else 'file',
                'size': item_stat.st_size,
                'modified': datetime.fromtimestamp(item_stat.st_mtime).isoformat(),
                'path': os.path.relpath(item_path, user_root).replace('\\', '/')
            }
            items.append(item_info)
        
        return jsonify({
            'path': os.path.relpath(full_path, user_root).replace('\\', '/'),
            'items': items
        }), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/api/files/download', methods=['GET'])
def download_file():
    user_id = request.args.get('user_id')
    relative_path = request.args.get('path', '')
    
    if not user_id:
        return jsonify({'error': 'user_id is required'}), 400
    
    if not relative_path:
        return jsonify({'error': 'path is required'}), 400
    
    user_root = get_user_root(user_id)
    full_path = validate_path(user_root, relative_path)
    
    if not os.path.exists(full_path):
        return jsonify({'error': 'File does not exist'}), 404
    
    if not os.path.isfile(full_path):
        return jsonify({'error': 'Path is not a file'}), 400
    
    try:
        return send_file(full_path, as_attachment=True, download_name=os.path.basename(full_path))
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/api/files/info', methods=['GET'])
def get_file_info():
    user_id = request.args.get('user_id')
    relative_path = request.args.get('path', '')
    
    if not user_id:
        return jsonify({'error': 'user_id is required'}), 400
    
    if not relative_path:
        return jsonify({'error': 'path is required'}), 400
    
    user_root = get_user_root(user_id)
    full_path = validate_path(user_root, relative_path)
    
    if not os.path.exists(full_path):
        return jsonify({'error': 'Path does not exist'}), 404
    
    try:
        stat_info = os.stat(full_path)
        is_dir = os.path.isdir(full_path)
        
        mime_type = None
        if not is_dir:
            mime_type, _ = mimetypes.guess_type(full_path)
        
        file_info = {
            'name': os.path.basename(full_path),
            'path': os.path.relpath(full_path, user_root).replace('\\', '/'),
            'type': 'directory' if is_dir else 'file',
            'size': stat_info.st_size,
            'created': datetime.fromtimestamp(stat_info.st_ctime).isoformat(),
            'modified': datetime.fromtimestamp(stat_info.st_mtime).isoformat(),
            'accessed': datetime.fromtimestamp(stat_info.st_atime).isoformat(),
            'mime_type': mime_type,
            'permissions': oct(stat_info.st_mode)[-3:]
        }
        
        return jsonify(file_info), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/api/files/upload', methods=['POST'])
def upload_file():
    user_id = request.form.get('user_id')
    relative_path = request.form.get('path', '')
    
    if not user_id:
        return jsonify({'error': 'user_id is required'}), 400
    
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400
    
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400
    
    user_root = get_user_root(user_id)
    upload_dir = validate_path(user_root, relative_path)
    
    if not os.path.exists(upload_dir):
        os.makedirs(upload_dir)
    
    if not os.path.isdir(upload_dir):
        return jsonify({'error': 'Upload path is not a directory'}), 400
    
    try:
        file_path = os.path.join(upload_dir, file.filename)
        file.save(file_path)
        
        return jsonify({
            'message': 'File uploaded successfully',
            'path': os.path.relpath(file_path, user_root).replace('\\', '/')
        }), 201
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True, port=5000)